patch:
diff --git a/drivers/acpi/battery.c b/drivers/acpi/battery.c
index 9a2c63b..82086ca 100644
--- a/drivers/acpi/battery.c
+++ b/drivers/acpi/battery.c
@@ -34,6 +34,7 @@
 #include <linux/dmi.h>
 #include <linux/slab.h>
 #include <linux/suspend.h>
+#include <linux/delay.h>
 #include <asm/unaligned.h>

 #include <linux/acpi.h>
@@ -672,6 +673,8 @@ static void acpi_battery_quirks(struct acpi_battery *battery)
 static int acpi_battery_update(struct acpi_battery *battery)
 {
 	int result, old_present = acpi_battery_present(battery);
+	int retry = 5;
+
 	result = acpi_battery_get_status(battery);
 	if (result)
 		return result;
@@ -682,7 +685,16 @@ static int acpi_battery_update(struct acpi_battery *battery)
 	}
 	if (!battery->update_time ||
 	    old_present != acpi_battery_present(battery)) {
+
+retry:
 		result = acpi_battery_get_info(battery);
+
+		if (result && retry) {
+			retry--;
+			mdelay(500);
+			goto retry;
+		}		
+
 		if (result)
 			return result;
 		acpi_battery_init_alarm(battery);
diff --git a/drivers/acpi/battery.c b/drivers/acpi/battery.c
index 9a2c63b..e8a68f1 100644
--- a/drivers/acpi/battery.c
+++ b/drivers/acpi/battery.c
@@ -34,6 +34,7 @@
 #include <linux/dmi.h>
 #include <linux/slab.h>
 #include <linux/suspend.h>
+#include <linux/delay.h>
 #include <asm/unaligned.h>

 #include <linux/acpi.h>
@@ -771,7 +772,7 @@ static struct dmi_system_id bat_dmi_table[] = {

 static int acpi_battery_add(struct acpi_device *device)
 {
-	int result = 0;
+	int result = 0, retry = 5;
 	struct acpi_battery *battery = NULL;

 	if (!device)
@@ -787,7 +788,16 @@ static int acpi_battery_add(struct acpi_device *device)
 	mutex_init(&battery->sysfs_lock);
 	if (acpi_has_method(battery->device->handle, "_BIX"))
 		set_bit(ACPI_BATTERY_XINFO_PRESENT, &battery->flags);
+
+retry_get_info:
 	result = acpi_battery_update(battery);
+
+	if (result && retry) {
+		msleep(10);
+		retry--;
+		goto retry_get_info;
+	}
+
 	if (result)
 		goto fail;
